const input = $('/start').first().json.message.text || "";
// Код для Code node в n8n

// 1. Парсинг команды (забираем третью часть как любые символы без пробелов)
const commandMatch = input.match(/^\/(add|a)\s+([^\s]+)\s+([^\s]+)(?:\s+([^\s]+))?$/i);
if (!commandMatch) {
  return { json: { error: '❌ Не правильный формат команды' } };
}

const [, , codeWord, link, thirdPart] = commandMatch;

// 2. Валидация code_word
if (!/^[a-zA-Zа-яА-ЯёЁ0-9-]+$/.test(codeWord)) {
  return { json: { error: '❌ Не правильное кодовое слово' } };
}

// 3. Валидация ссылки
const linkRegex = /^https:\/\/t\.me\/c\/(\d+)\/\d+$/;
if (!linkRegex.test(link)) {
  return { json: { error: '❌ Не правильный формат ссылки' } };
}

// 3.5 Валидация третьей части (проверка на запрещенные символы " и \)
if (thirdPart && /["\\]/.test(thirdPart)) {
  return { json: { error: '❌ В третьей части команды запрещено использовать кавычки (") и обратный слэш (\\)' } };
}

// 4. Сборка channel_id
const channelId = `-100${link.match(linkRegex)[1]}`;

// Сборка объекта parameters
const parameters = {};
if (thirdPart) {
  parameters.source_name = thirdPart;
}

// 5. Успешный результат
return {
  json: {
    channel_id: channelId,
    type_target: 'подписка на тг канал',
    parameters: parameters,
    code_word: codeWord,
    link_target: link
  }
};

// Передача данных и генерация уникального кода
return $('Добавление дожима').all().map(item => {
  item.json.target_code = Math.random().toString(36).substring(2, 7);
  return item;
});

const msg = $("Личное сообщение").first().json.message;
const text = msg.text || "";
const parts = text.split(" ");

let invite = null;

// Если после /start что-то есть
if (parts.length > 1) {
  const param = parts[1]; // Берем сам параметр после пробела

  // Регулярка: строго 5 символов (цифры и строчные латинские буквы)
  const match = param.match(/^[a-z0-9]{5}$/);

  if (match) {
    invite = param; 
  } else {
    // Генерируем ошибку и останавливаем сценарий
    return { json: { error: '❌ Неверный формат старт-параметра' } };
  }
}

return {
  user_id: msg.from.id,
  username: msg.from.username || "",
  first_name: msg.from.first_name || "",
  last_name: msg.from.last_name || "",
  target_code: invite || "",
  extra: {} 
};

// Собираем кнопки прямо из входящего массива $json
const buttons = $input.all().map(item => [
  {
    "text": item.json.channel_name,
    "callback_data": `select_channel:${item.json.channel_id}`
  }
]);

// Выдаем готовый body для Telegram
return [{
  json: {
    "chat_id": $('/start').first().json.message.from.id, // Сюда подставьте нужный ID пользователя
    "text": "📋 *Для какого канала хотите получить отчет:*",
    "parse_mode": "MarkdownV2",
    "reply_markup": {
      "inline_keyboard": buttons
    }
  }
}];

const BOT_USERNAME = $('Название бота').first().json.value;

// Функция экранирования текста для безопасного HTML в Telegram
const escape = text => !text ? '' : String(text)
  .replace(/&/g, '&amp;')
  .replace(/</g, '&lt;')
  .replace(/>/g, '&gt;');

// Форматирование одного блока данных
function formatEntry(item) {
  const data = item.json;
  const clicks = Number(data.clicks) || 0;
  const converted = Number(data.subscribed_with_gift) || 0;

  const linkTarget = data.link_target || '#';
  const botLink = data.bot_start_link || `https://t.me/${BOT_USERNAME}?start=${data.target_code || ''}`;
  const codeWord = escape(data.code_word);
  // ИСПРАВЛЕНО: Текст выводится как есть, без тега <code>
  const sourceName = escape(data.source_name || 'не указан');

  return `<b>🔑 Ключ: ${codeWord}</b>\n` +
         `📍 <b>Источник: ${sourceName}</b>\n` +
         `🎁 <b>Пост:</b> <a href='${linkTarget}'>${linkTarget}</a>\n` +
         `🔗 <b>Бот:</b> <code>${botLink}</code>\n` +
         `📊 <b>Статистика:</b> переходы: <b>${clicks}</b> | подарки: <b>${converted}</b>\n` +
         `───────────────────`;
}

// Сборка сообщений с жестким разделением через \n
function buildMessages(items) {
  const messages = [];
  let currentChunk = [];
  let currentLength = 0;

  for (const item of items) {
    const block = formatEntry(item);
    const delimiterLength = currentChunk.length > 0 ? 2 : 0;

    if (currentLength + delimiterLength + block.length > 3900 && currentChunk.length > 0) {
      messages.push(currentChunk.join('\n\n')); 
      currentChunk = [];
      currentLength = 0;
    }
    currentChunk.push(block);
    currentLength += (currentChunk.length > 1 ? 2 : 0) + block.length;
  }

  if (currentChunk.length > 0) {
    messages.push(currentChunk.join('\n\n'));
  }
  return messages;
}

// === Основная логика ===
const rawData = $input.all();

if (!rawData.length) {
  return [{ json: { text: '📭 Нет данных для отчета' } }];
}

const output = buildMessages(rawData).map((text, index) => {
  if (index === 0) {
    text = `<b>📊 Отчет по каналу "${$('Запрос разрешений').first().json['check:channel_name']}"</b>\n\n` + text;
  }
  return { json: { text } };
});

// Считаем общую статистику
const stats = rawData.reduce((acc, item) => {
  acc.clicks += Number(item.json.clicks) || 0;
  acc.converted += Number(item.json.subscribed_with_gift) || 0;
  acc.totalKeys += 1;
  return acc;
}, { clicks: 0, converted: 0, totalKeys: 0 });

const cr = stats.clicks ? Math.round((stats.converted / stats.clicks) * 100) : 0;

output.push({
  json: {
    text: `<b>📈 ИТОГО ПО КАНАЛУ</b>\n` +
          `───────────────────\n` +
          `🔑 Ключевых слов: <b>${stats.totalKeys}</b>\n` +
          `👥 Всего переходов: <b>${stats.clicks}</b>\n` +
          `✅ Получили подарок: <b>${stats.converted}</b>\n\n` +
          `🎯 <b>Конверсия:</b> <b>${cr}%</b>`
  }
});

return output;

// Простая защита полей для CSV (если в данных есть запятые или кавычки)
return $input.all().map(item => {
  const escaped = {};
  for (const [key, val] of Object.entries(item.json)) {
    const str = String(val ?? '');
    // Если есть запятая, кавычка или перенос — оборачиваем в кавычки и экранируем
    escaped[key] = /[",\n]/.test(str) ? `"${str.replace(/"/g, '""')}"` : str;
  }
  item.json = escaped;
  return item;
});

