COMMENT ON TABLE "AtGateInteractionLog" IS 'Хронология действий по взаимодействиям клиентов за подарками';
COMMENT ON COLUMN "AtGateInteractionLog".interaction_id IS 'ID взаимодействия из таблицы AtGateInteraction';
