COMMENT ON COLUMN "AtGateInteractionLog".created_at IS 'Дата и время совершения действия';

-- Индексы для быстрых выборок по конкретному взаимодействию и по времени
CREATE INDEX IF NOT EXISTS idx_log_interaction ON "AtGateInteractionLog"(interaction_id);
CREATE INDEX IF NOT EXISTS idx_log_created ON "AtGateInteractionLog"(created_at DESC);

