// 1. Читаем данные из ноды "Запрос цели"
const targetData = $('Запрос цели').first().json;

// 2. Читаем invite_link из предыдущей ноды
const inviteLink = $input.first().json.result?.invite_link || "";

// 3. Проверяем наличие параметра "напоминание"
const hasReminder = targetData.parameters && targetData.parameters.hasOwnProperty('напоминание');

// 4. Формируем значение для поля extra (сохраняя сам параметр с его содержимым)
const extraValue = hasReminder ? { "напоминание": targetData.parameters['напоминание'] } : "{}";

// Возвращаем итоговый объект
return [{
  json: {
    invite_link: inviteLink,
    status: "ожидание подачи заявки",
    reminder: hasReminder,
    extra: extraValue
  }
}];

const inputData = $input.first().json;

// Добавляем напоминание напрямую в объект parameters
inputData.parameters["напоминание"] = {
  "время": {
    "20": {
      "checked": 0,
      "ожидание подачи заявки": "🎯 Вы в одном шаге от цели! Переходите в канал, чтобы закончить."
    },
    "1440": {
      "checked": 0,
      "ожидание подачи заявки": "👋 Напоминаем, что ссылка на наш канал всё еще активна. Ждем вас!"
    }
  }
};

// Возвращаем объект со всеми исходными полями
return [{ json: inputData }];

const tz = $now.zoneName;
const sourceDate = "2026-06-04T09:19:27.738Z";

// Преобразуем в часовой пояс воркфлоу и нужный формат
const localDate = DateTime.fromISO(sourceDate)
  .setZone(tz)
  .toFormat('yyyy-MM-dd H:mm'); // 'H' — час без нуля (9), 'mm' — минуты с нулем (19)

return [{
  json: {
    current_timezone: tz,
    formatted_date: localDate // Выведет: "2026-06-04 12:19"
  }
}];

// Получаем часовой пояс
const tz = $now.zoneName;
const logs = $input.all();

// Сортируем логи по log_id
logs.sort((a, b) => a.json.log_id - b.json.log_id);

// Группируем логи по interaction_id
const groups = new Map();
for (const log of logs) {
  const id = log.json.interaction_id;
  const date = DateTime.fromISO(log.json.created_at).setZone(tz).toFormat('yyyy-MM-dd HH:mm:ss');
  const text = log.json.action_text;

  if (!groups.has(id)) groups.set(id, []);
  groups.get(id).push(`${date}\n${text}`);
}

// Преобразуем группы в Map с текстом логов
const logsMap = new Map();
for (const [id, entries] of groups) {
  logsMap.set(id, entries.join('\n\n'));
}

// Берем отчет и добавляем в него логи
const reports = $items('Запрос полей отчета1');
const result = [];

for (const report of reports) {
  const reportId = report.json.id;
  const logText = logsMap.get(reportId) || 'Логи отсутствуют';

  // Удаляем id и добавляем поле Отчет
  const { id, ...reportWithoutId } = report.json;
  result.push({
    ...reportWithoutId,
    Отчет: logText
  });
}

return result;
